-- 一键重建核心表并仅导入「操作系统(OS)」题库
-- 用法：在 Navicat 里打开 system 库 -> 新建查询 -> 粘贴本文件全部内容执行
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- 清理旧表（兼容你截图中的旧结构）
DROP TABLE IF EXISTS `recommendation_log`;
DROP TABLE IF EXISTS `user_behavior`;
DROP TABLE IF EXISTS `knowledge_point`;
DROP TABLE IF EXISTS `admin`;
DROP TABLE IF EXISTS `exercise`;
DROP TABLE IF EXISTS `user_answer`;
DROP TABLE IF EXISTS `sys_user`;

-- 按当前项目结构重建表
CREATE TABLE `sys_user` (
  `id` int PRIMARY KEY AUTO_INCREMENT,
  `username` varchar(50) NOT NULL,
  `password` varchar(100) NOT NULL,
  `name` varchar(100),
  `avatar` varchar(255),
  `role` varchar(20) NOT NULL,
  `subject` varchar(20) NOT NULL,
  `status` tinyint DEFAULT 1,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  UNIQUE KEY `uk_user_identity` (`username`,`role`,`subject`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `exercise` (
  `id` varchar(64) PRIMARY KEY,
  `subject` varchar(20) NOT NULL,
  `chapter` varchar(100) NOT NULL,
  `chapter_slug` varchar(100),
  `stem` text NOT NULL,
  `option_a` varchar(255),
  `option_b` varchar(255),
  `option_c` varchar(255),
  `option_d` varchar(255),
  `answer` varchar(4) NOT NULL,
  `analysis` text,
  `difficulty` int DEFAULT 2,
  `knowledge_points` text,
  `attachment_url` varchar(255),
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  KEY `idx_exercise_subject` (`subject`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `user_answer` (
  `id` bigint PRIMARY KEY AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `subject` varchar(20) NOT NULL,
  `exercise_id` varchar(64) NOT NULL,
  `is_correct` tinyint NOT NULL,
  `chosen_option` varchar(4),
  `correct_answer` varchar(4),
  `answered_at` datetime,
  KEY `idx_answer_user_subject` (`user_id`,`subject`),
  KEY `idx_answer_exercise` (`exercise_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


-- 仅导入 OS 题目（共 120 题）

SET FOREIGN_KEY_CHECKS = 1;
SELECT subject, COUNT(*) AS total FROM exercise GROUP BY subject;